#!/usr/bin/env bash
set -euo pipefail

SLACK_WEBHOOK_URL="${SLACK_WEBHOOK_URL:?Set SLACK_WEBHOOK_URL env var to your Slack Incoming Webhook URL}"

post() {
  local payload="$1"
  curl -sS -X POST \
    -H 'Content-type: application/json' \
    --data "$payload" \
    "$SLACK_WEBHOOK_URL"
  echo
}

echo "Posting optimized interactive-style Slack showcase cards..."

